1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	};
10	
11	const basePremium = (item: any): number => {
12	  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_PREMIUM;
13	  return BASE_PREMIUMS[item.type] ?? 0;
14	};
15	
16	const componentPremium = (items: any[]): number => {
17	  const components = items.filter((i: any) => COMPONENT_TYPES.has(i.type));
18	  const counts: Record<string, number> = {};
19	  for (const c of components) {
20	    counts[c.type] = (counts[c.type] ?? 0) + 1;
21	  }
22	  let total = 0;
23	  for (const count of Object.values(counts)) {
24	    if (count === 3) {
25	      total += BLOCK_PREMIUM;
26	    } else {
27	      total += count * COMPONENT_PREMIUM;
28	    }
29	  }
30	  return total;
31	};
32	
33	export const processScenario = (scenario: any): any => {
34	  const results = scenario.steps.map((step: any) => {
35	    const mainItems = step.items.filter((i: any) => !COMPONENT_TYPES.has(i.type));
36	    const mainTotal = mainItems.reduce(
37	      (sum: number, item: any) => sum + basePremium(item),
38	      0,
39	    );
40	    const compTotal = componentPremium(step.items);
41	    const premium = PROCESSING_FEE + mainTotal + compTotal;
42	    return { premium };
43	  });
44	  return { results };
45	};
